try {
  const inicio_validacion_cuw = Date.now(); // ms

  function isNonEmpty(v) {
    return v !== undefined && v !== null && String(v).trim() !== "";
  }

  function isTrueFlag(v) {
    const val = String(v || "").trim().toUpperCase();
    return val === "SI" || val === "TRUE" || val === "1";
  }

  // Por si algún select viene como objeto {name/label/nombre/...}
  function extractName(maybeObj) {
    if (!maybeObj || typeof maybeObj !== "object") return null;
    return (
      maybeObj.nombre ??
      maybeObj.name ??
      maybeObj.label ??
      maybeObj.text ??
      maybeObj.descripcion ??
      null
    );
  }

  const result = {};

  // TOMADOR: sección CREAR / sección PRINCIPAL
  const crearTomador = isTrueFlag(data.frm_tom_cc_crear_cliente_flag);

  const tom_tipo_documento =
    crearTomador && isNonEmpty(data.frm_tom_cc_tipo_documento)
      ? data.frm_tom_cc_tipo_documento
      : (data.frm_tom_tipo_documento ?? null);

  const tom_tipo_documento_nombre =
    crearTomador && isNonEmpty(data.frm_tom_cc_tipo_documento_nombre)
      ? data.frm_tom_cc_tipo_documento_nombre
      : (data.frm_tom_tipo_documento_nombre ?? null);

  const tom_num_documento =
    crearTomador && isNonEmpty(data.frm_tom_cc_num_documento)
      ? data.frm_tom_cc_num_documento
      : (data.frm_tom_num_documento ?? null);

  const tom_nombres_completos =
    crearTomador && isNonEmpty(data.frm_tom_cc_nombre_compania)
      ? data.frm_tom_cc_nombre_compania
      : (data.frm_tom_nombres_completos ?? null);

  const tom_tipo_empresa =
    crearTomador && isNonEmpty(data.frm_tom_cc_tipo_empresa)
      ? data.frm_tom_cc_tipo_empresa
      : (data.frm_tom_tipo_empresa ?? null);

  const tom_fecha_constitucion =
    crearTomador && isNonEmpty(data.frm_tom_cc_fecha_constitucion)
      ? data.frm_tom_cc_fecha_constitucion
      : (data.frm_tom_fecha_constitucion ?? null);

  const tom_correo_facturacion =
    crearTomador && isNonEmpty(data.frm_tom_cc_correo_facturacion)
      ? data.frm_tom_cc_correo_facturacion
      : (data.frm_tom_correo_facturacion ?? null);

  const tom_direccion =
    crearTomador && isNonEmpty(data.frm_tom_cc_direccion)
      ? data.frm_tom_cc_direccion
      : (data.frm_tom_direccion ?? null);

  const tom_telefono =
    crearTomador && isNonEmpty(data.frm_tom_cc_telefono)
      ? data.frm_tom_cc_telefono
      : (data.frm_tom_telefono ?? null);

  const tom_actividad_asegurada =
    crearTomador && isNonEmpty(data.frm_tom_cc_actividad_comercial)
      ? data.frm_tom_cc_actividad_comercial
      : (data.frm_tom_actividad_asegurada ?? null);

  // ✅ NUEVO: Departamento / Municipio (Tomador)
  const tom_departamento =
    crearTomador && isNonEmpty(data.frm_tom_cc_departamento)
      ? data.frm_tom_cc_departamento
      : (data.frm_tom_departamento ?? null);

  const tom_departamento_num =
    crearTomador && isNonEmpty(data.frm_tom_cc_departamento_num)
      ? data.frm_tom_cc_departamento_num
      : (data.frm_tom_departamento_num ?? null);

  const tom_departamento_nombre =
    crearTomador && isNonEmpty(data.frm_tom_cc_departamento_nombre)
      ? data.frm_tom_cc_departamento_nombre
      : (data.frm_tom_departamento_nombre ?? null);

  const tom_municipio =
    crearTomador && isNonEmpty(data.frm_tom_cc_municipio)
      ? data.frm_tom_cc_municipio
      : (data.frm_tom_municipio ?? null);

  const tom_municipio_nombre =
    crearTomador && isNonEmpty(data.frm_tom_cc_municipio_nombre)
      ? data.frm_tom_cc_municipio_nombre
      : (data.frm_tom_municipio_nombre ?? extractName(tom_municipio) ?? null);

  const tom_nombre   = data.frm_tom_nombre ?? null;
  const tom_apellido = data.frm_tom_apellido ?? null;

  result.frm_tom_tipo_documento        = tom_tipo_documento;
  result.frm_tom_tipo_documento_nombre = tom_tipo_documento_nombre;
  result.frm_tom_num_documento         = tom_num_documento;
  result.frm_tom_nombres_completos     = tom_nombres_completos;
  result.frm_tom_tipo_empresa          = tom_tipo_empresa;
  result.frm_tom_fecha_constitucion    = tom_fecha_constitucion;
  result.frm_tom_correo_facturacion    = tom_correo_facturacion;
  result.frm_tom_direccion             = tom_direccion;
  result.frm_tom_telefono              = tom_telefono;
  result.frm_tom_actividad_asegurada   = tom_actividad_asegurada;
  result.frm_tom_nombre                = tom_nombre;
  result.frm_tom_apellido              = tom_apellido;

  // ✅ NUEVO: asignaciones Tomador
  result.frm_tom_departamento          = tom_departamento;
  result.frm_tom_departamento_num      = tom_departamento_num;
  result.frm_tom_departamento_nombre   = tom_departamento_nombre;
  result.frm_tom_municipio             = tom_municipio;
  result.frm_tom_municipio_nombre      = tom_municipio_nombre;

  // ASEGURADO
  const crearAsegurado = isTrueFlag(data.frm_aseg_cc_crear_cliente_flag);

  const aseg_tipo_documento =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_tipo_documento)
      ? data.frm_aseg_cc_tipo_documento
      : (data.frm_aseg_tipo_documento ?? null);

  const aseg_tipo_documento_nombre =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_tipo_documento_nombre)
      ? data.frm_aseg_cc_tipo_documento_nombre
      : (data.frm_aseg_tipo_documento_nombre ?? null);

  const aseg_num_documento =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_num_documento)
      ? data.frm_aseg_cc_num_documento
      : (data.frm_aseg_num_documento ?? null);

  const aseg_nombres_completos =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_nombre_compania)
      ? data.frm_aseg_cc_nombre_compania
      : (data.frm_aseg_nombres_completos ?? null);

  const aseg_tipo_empresa =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_tipo_empresa)
      ? data.frm_aseg_cc_tipo_empresa
      : (data.frm_aseg_tipo_empresa ?? null);

  const aseg_fecha_constitucion =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_fecha_constitucion)
      ? data.frm_aseg_cc_fecha_constitucion
      : (data.frm_aseg_fecha_constitucion ?? null);

  const aseg_correo_facturacion =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_correo_facturacion)
      ? data.frm_aseg_cc_correo_facturacion
      : (data.frm_aseg_correo_facturacion ?? null);

  const aseg_direccion =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_direccion)
      ? data.frm_aseg_cc_direccion
      : (data.frm_aseg_direccion ?? null);

  const aseg_telefono =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_telefono)
      ? data.frm_aseg_cc_telefono
      : (data.frm_aseg_telefono ?? null);

  const aseg_actividad_comercial =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_actividad_comercial)
      ? data.frm_aseg_cc_actividad_comercial
      : (data.frm_aseg_actividad_comercial ?? null);

  // ✅ NUEVO: Departamento / Municipio (Asegurado)
  const aseg_departamento =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_departamento)
      ? data.frm_aseg_cc_departamento
      : (data.frm_aseg_departamento ?? null);

  const aseg_departamento_num =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_departamento_num)
      ? data.frm_aseg_cc_departamento_num
      : (data.frm_aseg_departamento_num ?? null);

  const aseg_departamento_nombre =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_departamento_nombre)
      ? data.frm_aseg_cc_departamento_nombre
      : (data.frm_aseg_departamento_nombre ?? null);

  const aseg_municipio =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_municipio)
      ? data.frm_aseg_cc_municipio
      : (data.frm_aseg_municipio ?? null);

  const aseg_municipio_nombre =
    crearAsegurado && isNonEmpty(data.frm_aseg_cc_municipio_nombre)
      ? data.frm_aseg_cc_municipio_nombre
      : (data.frm_aseg_municipio_nombre ?? extractName(aseg_municipio) ?? null);

  const aseg_nombre   = data.frm_aseg_nombre ?? null;
  const aseg_apellido = data.frm_aseg_apellido ?? null;

  result.frm_aseg_tipo_documento        = aseg_tipo_documento;
  result.frm_aseg_tipo_documento_nombre = aseg_tipo_documento_nombre;
  result.frm_aseg_num_documento         = aseg_num_documento;
  result.frm_aseg_nombres_completos     = aseg_nombres_completos;
  result.frm_aseg_tipo_empresa          = aseg_tipo_empresa;
  result.frm_aseg_fecha_constitucion    = aseg_fecha_constitucion;
  result.frm_aseg_correo_facturacion    = aseg_correo_facturacion;
  result.frm_aseg_direccion             = aseg_direccion;
  result.frm_aseg_telefono              = aseg_telefono;
  result.frm_aseg_actividad_comercial   = aseg_actividad_comercial;
  result.frm_aseg_nombre                = aseg_nombre;
  result.frm_aseg_apellido              = aseg_apellido;

  // ✅ NUEVO: asignaciones Asegurado
  result.frm_aseg_departamento          = aseg_departamento;
  result.frm_aseg_departamento_num      = aseg_departamento_num;
  result.frm_aseg_departamento_nombre   = aseg_departamento_nombre;
  result.frm_aseg_municipio             = aseg_municipio;
  result.frm_aseg_municipio_nombre      = aseg_municipio_nombre;

  // SI EL ASEGURADO ES EL MISMO TOMADOR
  const esTomador = isTrueFlag(data.frm_tom_asegurado_es_tomador_flag);

  if (esTomador) {
    if (isNonEmpty(tom_tipo_documento))        result.frm_aseg_tipo_documento        = tom_tipo_documento;
    if (isNonEmpty(tom_tipo_documento_nombre)) result.frm_aseg_tipo_documento_nombre = tom_tipo_documento_nombre;
    if (isNonEmpty(tom_num_documento))         result.frm_aseg_num_documento         = tom_num_documento;
    if (isNonEmpty(tom_nombres_completos))     result.frm_aseg_nombres_completos     = tom_nombres_completos;
    if (isNonEmpty(tom_tipo_empresa))          result.frm_aseg_tipo_empresa          = tom_tipo_empresa;
    if (isNonEmpty(tom_fecha_constitucion))    result.frm_aseg_fecha_constitucion    = tom_fecha_constitucion;
    if (isNonEmpty(tom_correo_facturacion))    result.frm_aseg_correo_facturacion    = tom_correo_facturacion;
    if (isNonEmpty(tom_direccion))             result.frm_aseg_direccion             = tom_direccion;
    if (isNonEmpty(tom_telefono))              result.frm_aseg_telefono              = tom_telefono;
    if (isNonEmpty(tom_actividad_asegurada))   result.frm_aseg_actividad_comercial   = tom_actividad_asegurada;

    if (isNonEmpty(tom_nombre))   result.frm_aseg_nombre   = tom_nombre;
    if (isNonEmpty(tom_apellido)) result.frm_aseg_apellido = tom_apellido;

    // ✅ NUEVO: copiar también ubicación
    if (isNonEmpty(tom_departamento))        result.frm_aseg_departamento        = tom_departamento;
    if (isNonEmpty(tom_departamento_num))    result.frm_aseg_departamento_num    = tom_departamento_num;
    if (isNonEmpty(tom_departamento_nombre)) result.frm_aseg_departamento_nombre = tom_departamento_nombre;
    if (isNonEmpty(tom_municipio))           result.frm_aseg_municipio           = tom_municipio;
    if (isNonEmpty(tom_municipio_nombre))    result.frm_aseg_municipio_nombre    = tom_municipio_nombre;
  }

  // ⏱ tiempo en segundos
  const fin_validacion_cuw = Date.now();
  result.tiempo_validacion_cuw = (fin_validacion_cuw - inicio_validacion_cuw) / 1000;

  return result;

} catch (e) {
  return {};
}
